import{_ as i,c as l,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const d=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/PublicAPIs-开发工具.md","filePath":"github汇总/开发工具/PublicAPIs-开发工具.md"}'),t={name:"github汇总/开发工具/PublicAPIs-开发工具.md"};function h(s,a,n,o,c,b){return e(),l("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Public APIs</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>public-apis Community</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>找API困难、API质量参差不齐、需要付费、缺少分类整理</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>社区手动维护的免费API集合</li><li>涵盖数十个分类</li><li>每个API包含描述、认证要求、HTTPS支持、CORS支持等信息</li><li>GitHub上Star数最多的仓库之一</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>社区维护，质量可靠</li><li>涵盖分类广泛，几乎无所不包</li><li>GitHub上Star数最多的仓库之一</li><li>完全免费使用</li><li>信息完整，易于筛选</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>GitHub上Star数最多的仓库之一</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/public-apis/public-apis" target="_blank" rel="noreferrer">https://github.com/public-apis/public-apis</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="不适用原因说明" tabindex="-1">不适用原因说明 <a class="header-anchor" href="#不适用原因说明" aria-label="Permalink to “不适用原因说明”">​</a></h2><p>Public APIs是一个API列表集合，不是需要安装部署的软件项目，而是一个供查阅的资源列表。</p><h2 id="可执行的最小上手路径" tabindex="-1">可执行的最小上手路径 <a class="header-anchor" href="#可执行的最小上手路径" aria-label="Permalink to “可执行的最小上手路径”">​</a></h2><ol><li>访问项目GitHub页面或官方网站</li><li>浏览分类，找到感兴趣的API</li><li>点击API链接，查看详细文档</li><li>根据API文档进行调用</li></ol><h2 id="环境与权限要求" tabindex="-1">环境与权限要求 <a class="header-anchor" href="#环境与权限要求" aria-label="Permalink to “环境与权限要求”">​</a></h2><ul><li>能够访问GitHub（如无法访问，参考 <a href="/网络环境.html">海外网络环境配置 →</a>）</li><li>浏览器或HTTP客户端</li><li>部分API可能需要API Key</li></ul><h2 id="成功验证方式" tabindex="-1">成功验证方式 <a class="header-anchor" href="#成功验证方式" aria-label="Permalink to “成功验证方式”">​</a></h2><p>成功调用一个API并获得预期响应。</p><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：无法访问GitHub</p><ul><li><strong>可能原因</strong>：网络问题</li><li><strong>解决步骤</strong>：参考 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul></li><li><p><strong>现象</strong>：API调用失败</p><ul><li><strong>可能原因</strong>：API已失效或需要认证</li><li><strong>解决步骤</strong>：查看API最新状态，确认是否需要API Key</li></ul></li><li><p><strong>现象</strong>：找不到需要的API</p><ul><li><strong>可能原因</strong>：分类浏览不充分</li><li><strong>解决步骤</strong>：使用页面搜索功能，或提交Issue请求添加</li></ul></li></ol><h2 id="官方文档与补充入口" tabindex="-1">官方文档与补充入口 <a class="header-anchor" href="#官方文档与补充入口" aria-label="Permalink to “官方文档与补充入口”">​</a></h2><p>官方GitHub仓库：<a href="https://github.com/public-apis/public-apis" target="_blank" rel="noreferrer">https://github.com/public-apis/public-apis</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',29)]))}const P=i(t,[["render",h]]);export{d as __pageData,P as default};
